{
  "name": "Weatherization Assistance Program (WAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Household income at or below 200% of the Federal Poverty Level (FPL). Alternative qualification: receipt of Supplemental Security Income (SSI). Exact dollar amounts vary annually with FPL updates and by household size (e.g., for 2026, consult current HHS FPL guidelines as specific table not in sources; typically ~$30,120 for 1 person, ~$40,880 for 2, scaling up). Priority given to elderly, households with disabilities, and families with children.[1][2][3][7]",
    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": ["Eligible home types: single-family, manufactured homes, appropriate multi-family units (campers and non-stationary trailers ineligible).[1][3]", "Homeowners and renters qualify; renters need landlord agreement.[1]"]
  },
  "benefits": {
    "type": "service",
    "value": "No-cost home energy efficiency improvements based on energy audit results, including: air and duct sealing, wall/floor/attic insulation, HVAC system improvements, energy-efficient lighting, hot water tank/pipe insulation, water conservation devices. Does not cover pre-existing structural issues like roofing, walls, flooring holes, underpinning, or ceiling replacement.[1][3]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact local community action agency by county (full list at https://gefa.georgia.gov/weatherization).[4]", "Examples: CSRA EOA at (706) 945-1616 or www.csraeoa.org (download application); Savannah/Chatham via Action Pact; Middle Georgia Community Action Agency.[1][3][8]"],
    "processing_time": "Not specified; energy audit follows qualification, then measures installed by contractors.",
    "waitlist": "Due to high demand, there may be a waiting list.[4]",
    "forms": ["Application downloadable from local agency sites, e.g., CSRA EOA website.[3]"],
    "documents": ["Proof of income (to verify ≤200% FPL or SSI), proof of residency, landlord permission if renter (inferred from process). Specifics determined by local agency.[2][3][4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available county-wide via local agencies; must contact agency for your county.",
    "regional_variations": "Administered by different local community action agencies per county/region (e.g., Action Pact in Savannah/Chatham, CSRA EOA in CSRA counties, Middle Georgia CAA); same core eligibility/benefits, but different contacts, potential wait time variations.[1][3][4][8]",
    "offices_or_providers": ["Local providers listed by county at https://gefa.georgia.gov/weatherization.[4]"]
  },
  "official_source": "https://gefa.georgia.gov/weatherization",
  "gotchas": ["Renters need landlord agreement; ineligible for campers/non-stationary trailers or pre-existing structural repairs (e.g., no roof/wall replacement); priority to elderly/disabled/families with children may create longer waits for others; must contact specific county agency, not centralized.[1][3][4]"],
  "data_shape_notes": "County-specific local agencies handle intake/processing; uniform 200% FPL/SSI eligibility statewide but priority tiers and waitlists vary regionally; services audit-driven, not fixed dollar amounts."
}

{
  "name": "Georgia State Health Insurance Assistance Program (Georgia SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income or asset limits; open to all Medicare beneficiaries, their families, and caregivers, including those with limited incomes, under age 65 with disabilities, or dually eligible for Medicare and Medicaid[2][3][8]",
    "asset_limits": "No asset limits or tests apply; no specification of what counts or is exempt as limits do not exist[2][3]",
    "other_requirements": ["Must be a Medicare beneficiary or caregiver/family member of one", "Georgia resident (inferred from program scope)", "Services focus on Medicare-related issues[2][3][8]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free, unbiased one-on-one counseling and assistance on Medicare (Parts A, B, C, D), Medigap, Medicaid, prescription drug programs, long-term care insurance, claims/billing resolution, appeals, enrollment in plans and financial assistance programs (e.g., Medicare Savings Programs like QMB/SLMB/QI, Extra Help/Low Income Subsidy), fraud prevention via SMP, public education presentations, and referrals; no fixed dollar amounts or hours specified[2][3][5][6][8][10]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-866-552-4464 (select option 4)", "Website: ship.georgia.gov (for contact, counseling requests, events)", "Email: varies by local provider (e.g., lplatter@accaging.org for Athens area)", "In-person: Local sessions via community outreach, presentations, or partner offices (e.g., Athens Community Council on Aging at 706-549-4850)", "No specific online form or mail application mentioned; contact to schedule[5][7][8][9]"],
    "processing_time": "Not specified; services provided via phone/face-to-face sessions upon contact (Monday-Friday 8am-5pm)[9]",
    "waitlist": null,
    "forms": ["No specific forms required; may assist with Medicare enrollment or assistance program applications during counseling[2][3]"],
    "documents": ["Medicare card, Medicare Summary Notices, Explanation of Benefits, medical bills, or insurance documents for personalized counseling; not required to start[10]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Administered statewide by Georgia Department of Human Services Division of Aging Services with local providers (e.g., Athens Community Council on Aging); local offices handle in-person services and may have specific contacts/phone numbers, but core services uniform[2][5][8]",
    "offices_or_providers": ["Statewide helpline; local examples: Athens (706-549-4850, lplatter@accaging.org)[5]"]
  },
  "official_source": "https://aging.georgia.gov/georgia-ship and https://ship.georgia.gov[8][9][10]",
  "gotchas": ["Not an insurance provider or seller—provides information only, does not sell plans[10]", "Volunteer-based, so availability may depend on local counselors[5][8]", "Focused exclusively on Medicare/health insurance counseling, not direct healthcare or financial aid[2][3]", "Must select option 4 on helpline for SHIP[7][8]", "Supports low-income applications (e.g., QMB up to ~$1,478/month single, SLMB/QI higher) but SHIP itself has no limits[4]"],
  "data_shape_notes": "no income/asset test; volunteer counseling network statewide with local variation in access points; services are advisory/enrollment assistance only, not direct benefits"
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to all residents regardless of financial status",
    "asset_limits": "No asset limits; no financial eligibility requirements",
    "other_requirements": ["Must be a resident of a long-term care facility in Georgia (nursing homes, personal care homes, assisted living facilities, community living arrangements, or intermediate care facilities for persons with intellectual and developmental disabilities)", "Complaint or concern must affect the resident; intervention requires direct permission of the resident or their representative"][3][4][5][6]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Informal investigation and resolution of complaints; advocacy for residents' rights and wishes; routine facility visits to monitor conditions; education on long-term care issues, laws, and policies; provision of resources and materials; promotion of family and community involvement; coordination with other agencies; staff education on resident rights",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-866-552-4464 (select option 5)", "Website: https://www.georgiaombudsman.org", "Local Area Agencies on Aging or contracted non-profits (e.g., Athens Community Council on Aging at 706.549.4850 for East region)", "In-person or routine facility visits by ombudsmen"],
    "processing_time": "Informal and immediate response aimed at quick resolution; no formal processing timeline specified",
    "waitlist": null,
    "forms": [],
    "documents": ["No specific documents required; provide details of the complaint or concern, resident's permission if needed, and facility information"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to residents in qualifying long-term care facilities across Georgia",
    "regional_variations": "Services delivered through contracts with Area Agencies on Aging (AAA) and non-profit organizations; local offices handle specific regions (e.g., East region covering 25 counties from Athens to Gwinnett via ACCA)",
    "offices_or_providers": ["Office of the State Long-Term Care Ombudsman (under Division of Aging Services)", "Area Agencies on Aging", "Non-profit organizations", "Example: Athens Community Council on Aging (706.549.4850)"]
  },
  "official_source": "https://aging.georgia.gov/programs-and-services/long-term-care-ombudsman-program",
  "gotchas": ["Not a direct service provider (e.g., no healthcare, housing, or financial aid); focuses on advocacy and complaint resolution only", "Requires resident's permission for intervention; cannot act without it", "Not for facility staff or certification (that's for volunteers/ombudsmen)", "Informal process, not formal legal action or guaranteed outcomes", "Families must contact for their loved one's specific facility issues, not general advice"],
  "data_shape_notes": "no income or asset test; open to all LTC facility residents; advocacy-only, not financial or direct services; delivered regionally via AAAs and non-profits; volunteer ombudsman certification is separate intensive training process"
}
